struct SlidingSum {
    vector<int> buf;
    int window;
    SlidingSum(int w) : window(w) {}
    void add(int x) {
        buf.push_back(x);
        if ((int)buf.size() > window) {
            buf.erase(buf.begin());
        }
    }
    int sum() const {
        int s = 0;
        for (int i = 0; i < (int)buf.size(); i++) s += buf[i];
        return s;
    }
    int count() const {
        return (int)buf.size();
    }
};

