    var step: Int

    def __init__(out self, start: Int, s: Int):
        self.value = start
        self.step = s

    def up(mut self):
        self.value = self.value + self.step

    def down(mut self):
        self.value = self.value - self.step

    def setStep(mut self, s: Int):
        self.step = s

    def get(self) -> Int:
        return self.value

