struct Vec4 {
    double a;
    double b;
    double c;
    double d;
    Vec4(double a_, double b_, double c_, double d_) : a(a_), b(b_), c(c_), d(d_) {}
    void add(const Vec4& o) {
        a += o.a; b += o.b; c += o.c; d += o.d;
    }
    void scale(double s) {
        a *= s; b *= s; c *= s; d *= s;
    }
    double dot(const Vec4& o) const {
        return a*o.a + b*o.b + c*o.c + d*o.d;
    }
    double sum() const {
        return a + b + c + d;
    }
};

