struct GridPoint {
    int x;
    int y;
    GridPoint(int x_, int y_) : x(x_), y(y_) {}
    void move(int dx, int dy) {
        x = x + dx;
        y = y + dy;
    }
    int manhattan(const GridPoint& o) const {
        int ax = x - o.x; if (ax < 0) ax = -ax;
        int ay = y - o.y; if (ay < 0) ay = -ay;
        return ax + ay;
    }
};

