@fieldwise_init
struct GridPoint(Copyable, Movable):
    var x: Int
    var y: Int

    def move(mut self, dx: Int, dy: Int):
        self.x = self.x + dx
        self.y = self.y + dy

    def manhattan(self, o: GridPoint) -> Int:
        var ax = self.x - o.x
        if ax < 0:
            ax = -ax
        var ay = self.y - o.y
        if ay < 0:
            ay = -ay
        return ax + ay

